import{_ as l,c as a,a7 as i,o as r}from"./chunks/framework.Bfq_PhNx.js";const c=JSON.parse('{"title":"DV-07-Basic Charts","description":"","frontmatter":{"date":"2025-12-30T00:00:00.000Z","title":"DV-07-Basic Charts","status":"DONE","author":["AllenYGY"],"tags":["NOTE","DataVisualization"],"publish":true,"slidev":false},"headers":[],"relativePath":"posts/Data Analysis/Data Visualization/DV-07-Basic Charts.md","filePath":"posts/Data Analysis/Data Visualization/DV-07-Basic Charts.md","lastUpdated":null}'),e={name:"posts/Data Analysis/Data Visualization/DV-07-Basic Charts.md"};function s(o,t,n,u,h,d){return r(),a("div",null,[...t[0]||(t[0]=[i('<hr><h1 id="dv-07-basic-charts" tabindex="-1">DV-07-Basic Charts <a class="header-anchor" href="#dv-07-basic-charts" aria-label="Permalink to &quot;DV-07-Basic Charts&quot;">​</a></h1><ul><li>Point charts <ul><li>scatterplot, multi-class scatterplot, etc.</li></ul></li><li>Line charts <ul><li>line chart, bar chart, stacked bar chart, etc.</li></ul></li><li>Area charts <ul><li>bubble chart, pie chart, etc.</li></ul></li><li>Composite charts</li></ul><hr><table tabindex="0"><thead><tr><th>Chart</th><th>主要用途</th></tr></thead><tbody><tr><td>Scatterplot</td><td>两个定量变量的关系</td></tr><tr><td>Line chart</td><td>时间趋势</td></tr><tr><td>Bar chart</td><td>类别比较</td></tr><tr><td>Box plot</td><td>分布 &amp; 异常</td></tr><tr><td>Stacked bar</td><td>构成 + 总量</td></tr><tr><td>Normalized stacked bar</td><td>构成比例</td></tr><tr><td>Pie chart</td><td>简单构成</td></tr><tr><td>Bubble chart</td><td>面积编码（不推荐）</td></tr><tr><td>Streamgraph</td><td>时间连续变化</td></tr></tbody></table><h2 id="line-chart" tabindex="-1">Line Chart <a class="header-anchor" href="#line-chart" aria-label="Permalink to &quot;Line Chart&quot;">​</a></h2><p>看 <strong>随顺序（通常是时间）变化的趋势</strong></p><ul><li><strong>Data</strong><ul><li>1 ordered key（时间）</li><li>1 quantitative value</li></ul></li><li><strong>Mark</strong><ul><li>Line + points</li></ul></li><li><strong>Channel</strong><ul><li>Position + connected line</li></ul></li><li><strong>Tasks</strong><ul><li>Trend</li><li>Change over time</li></ul></li><li>用在： <ul><li>股票走势</li><li>温度随时间变化</li></ul></li><li>不要用在： <ul><li><strong>categorical key</strong>（会暗示“趋势”，违反 expressiveness principle）</li></ul></li></ul><p>The optimal aspect ratio for a line chart aims to make the average orientation of line segments close to 45 degrees.<br> This “banking to 45 degrees” principle improves perceptual accuracy when judging trends and slopes, reducing visual distortion caused by inappropriate aspect ratios.</p><hr><h2 id="bar-chart-柱状图" tabindex="-1">Bar Chart（柱状图） <a class="header-anchor" href="#bar-chart-柱状图" aria-label="Permalink to &quot;Bar Chart（柱状图）&quot;">​</a></h2><p><strong>用来干什么？</strong><br><strong>类别之间的数值比较</strong></p><ul><li><strong>Data</strong><ul><li>1 categorical key</li><li>1 quantitative value</li></ul></li><li><strong>Mark</strong><ul><li>Bars</li></ul></li><li><strong>Channel</strong><ul><li>Length (aligned) —— 非常准确</li></ul></li><li><strong>Tasks</strong><ul><li>Compare values</li><li>Rank</li></ul></li></ul><p>用在：</p><ul><li>各国 GDP</li><li>各类别数量</li></ul><p>📌 关键细节（常考）：</p><ul><li><strong>排序 vs 不排序</strong><ul><li>排序后更容易看排名</li><li>不排序更容易查找具体类别</li></ul></li></ul><hr><h2 id="box-plot-箱线图" tabindex="-1">Box Plot（箱线图） <a class="header-anchor" href="#box-plot-箱线图" aria-label="Permalink to &quot;Box Plot（箱线图）&quot;">​</a></h2><p><strong>用来干什么？</strong><br> 👉 <strong>比较分布，而不是单个数值</strong></p><ul><li><strong>Data</strong><ul><li>1 quantitative</li><li>可加 1 categorical</li></ul></li><li><strong>Mark</strong><ul><li>Box</li></ul></li><li><strong>What it shows</strong><ul><li>Median</li><li>Quartiles</li><li>IQR</li><li>Outliers</li></ul></li><li><strong>Tasks</strong><ul><li>Compare distributions</li><li>Identify outliers</li></ul></li></ul><p>✅ 用在：</p><ul><li>不同组成绩分布</li><li>不同地区收入分布</li></ul><p>❌ 不适合：</p><ul><li>精确数值读取</li></ul><hr><h2 id="stacked-bar-chart-堆叠柱状图" tabindex="-1">Stacked Bar Chart（堆叠柱状图） <a class="header-anchor" href="#stacked-bar-chart-堆叠柱状图" aria-label="Permalink to &quot;Stacked Bar Chart（堆叠柱状图）&quot;">​</a></h2><p><strong>用来干什么？</strong><br> 👉 <strong>Part-to-whole（组成关系） + 类别比较</strong></p><ul><li><strong>Data</strong><ul><li>2 categorical + 1 quantitative</li></ul></li><li><strong>Task</strong><ul><li>看总量</li><li>看组成</li></ul></li></ul><p>⚠️ 注意：</p><ul><li>中间部分不容易比较</li><li>类别不宜太多</li></ul><hr><h2 id="normalized-stacked-bar-chart-归一化堆叠柱" tabindex="-1">Normalized Stacked Bar Chart（归一化堆叠柱） <a class="header-anchor" href="#normalized-stacked-bar-chart-归一化堆叠柱" aria-label="Permalink to &quot;Normalized Stacked Bar Chart（归一化堆叠柱）&quot;">​</a></h2><p><strong>用来干什么？</strong><br> 👉 <strong>只看比例，不看总量</strong></p><ul><li>每根柱子高度 = 100%</li><li>相当于多个 pie chart 的替代方案</li></ul><p>✅ 用在：</p><ul><li>构成比例对比（各国产业结构）</li></ul><hr><h2 id="pie-chart-饼图" tabindex="-1">Pie Chart（饼图） <a class="header-anchor" href="#pie-chart-饼图" aria-label="Permalink to &quot;Pie Chart（饼图）&quot;">​</a></h2><p><strong>用来干什么？</strong></p><ul><li><p><strong>简单的 part-to-whole</strong></p></li><li><p><strong>Data</strong></p><ul><li>1 categorical, 1 quantitative</li></ul></li><li><p><strong>Channel</strong></p><ul><li>Angle / area（不准确）</li></ul></li></ul><p>⚠️ 限制（老师明确说）：</p><ul><li>不适合精确比较</li><li>切片不要多</li><li>只在非常简单时使用</li></ul><hr><h2 id="bubble-chart-气泡图" tabindex="-1">Bubble Chart（气泡图） <a class="header-anchor" href="#bubble-chart-气泡图" aria-label="Permalink to &quot;Bubble Chart（气泡图）&quot;">​</a></h2><p><strong>用来干什么？</strong></p><ul><li><p>用 <strong>面积</strong> 表示数值大小（但不准确）</p></li><li><p><strong>Problem</strong></p><ul><li>人对面积感知差</li><li>难比较</li></ul></li><li><p><strong>结论</strong></p><ul><li><strong>Seldomly used in visual analytics</strong></li></ul></li></ul><p>📌 考试态度：</p><blockquote><p>知道它存在，但要知道它“不推荐”。</p></blockquote><hr><h2 id="streamgraph-流图" tabindex="-1">Streamgraph（流图） <a class="header-anchor" href="#streamgraph-流图" aria-label="Permalink to &quot;Streamgraph（流图）&quot;">​</a></h2><p><strong>用来干什么？</strong> 强调 <strong>时间上的整体变化与连续性</strong></p><ul><li><p><strong>Data</strong></p><ul><li>时间 + 类别 + 数值</li></ul></li><li><p><strong>Task</strong></p><ul><li>Overall temporal patterns</li></ul></li><li><p><strong>Limit</strong></p><ul><li>不适合精确比较</li></ul></li><li><p>❓ categorical key + quantitative value → <strong>Bar chart</strong></p></li><li><p>❓ ordered key（time）+ quantitative → <strong>Line chart</strong></p></li><li><p>❓ distribution comparison → <strong>Box plot</strong></p></li><li><p>❓ part-to-whole → <strong>Stacked bar / pie</strong></p></li><li><p>❓ correlation → <strong>Scatterplot</strong></p></li></ul><hr>',54)])])}const g=l(e,[["render",s]]);export{c as __pageData,g as default};
